/* Minimal, self-authored, dependency-free polling shim for the monitoring UI (M7.6).
 *
 * This is NOT the full HTMX library. We intentionally do NOT vendor the ~50KB upstream
 * htmx.min.js: the monitoring dashboards use only a tiny attribute subset, and shipping a
 * small audited shim (served locally, no CDN) keeps the attack surface minimal — the design's
 * stated posture. It implements exactly the attributes the dashboards rely on:
 *
 *   hx-get="<url>"                 fetch <url> and replace the element's innerHTML
 *   hx-trigger="load"             fetch once on page load (default if hx-trigger absent)
 *   hx-trigger="every Ns"         fetch on load, then poll every N seconds
 *   hx-swap="innerHTML"           the only supported swap (default)
 *
 * Every request carries the `HX-Request: true` header so the server returns an inner fragment
 * (not the full page). Failures are swallowed (the stale fragment stays) so a transient blip
 * never blanks the dashboard.
 */
(function () {
  "use strict";

  function swap(el) {
    var url = el.getAttribute("hx-get");
    if (!url) return;
    fetch(url, { headers: { "HX-Request": "true" }, credentials: "same-origin" })
      .then(function (r) { return r.ok ? r.text() : Promise.reject(r.status); })
      .then(function (html) { el.innerHTML = html; })
      .catch(function () { /* keep the last good fragment on error */ });
  }

  function wire(el) {
    var trigger = (el.getAttribute("hx-trigger") || "load").trim();
    swap(el); // initial load
    var m = /^every\s+(\d+)s$/.exec(trigger);
    if (m) {
      var seconds = parseInt(m[1], 10);
      if (seconds > 0) setInterval(function () { swap(el); }, seconds * 1000);
    }
  }

  function init() {
    var nodes = document.querySelectorAll("[hx-get]");
    for (var i = 0; i < nodes.length; i++) wire(nodes[i]);
  }

  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", init);
  } else {
    init();
  }
})();
